import streamlit as st

st.title("Les bases de Streamlit")

st.subheader("Afficher du texte:")

st.write('''
st.info()\n
st.success()\n
st.text()\n
st.error()\n
st.header()\n
st.warning()\n
st.exception()
''')

e = Exception("message de l'exception")
st.exception(e)

st.subheader("Les inputs:")

st.number_input('Entrez un nombre:', min_value=1)
st.text_input('Entrez un texte:')
st.time_input('Heure:')
st.camera_input('Caméra:')

st.subheader("Colonnes:")

col1,col2,col3 = st.columns(3)

with col1:
    st.write("col1")

with col2:
    st.image('07-Streamlit/streamlit.png', width=100)

with col3:
    st.write('col3')

st.subheader('Bouton:')

result = st.button('Cliquez ici', type="primary")

if result:
    st.write('Vous avez cliquez...........')

st.subheader('Checkbox (case à cocher)')

cocher = st.checkbox('ADMIN', key='ADMIN')

if cocher:
    st.write(cocher)

st.subheader('Radio Button:')

radio = st.radio("Profile", ['CONSULTANT','MANAGER','DEVELOPPEUR'], key='profile', horizontal=True)

if radio:
    st.write(radio)

st.subheader('Multiselection (dropdown list)')

couleurs = st.multiselect('Choisir vos couleurs',
                           ['Rouge','Vert','Noir','Blanc'],
                             ['Vert','Noir'])

st.write(couleurs)

st.subheader('Expander:')

couleurs = ['Rouge', 'Noir', 'Blanc']

with st.expander('Animal'):
    st.selectbox('Choisir couleur', couleurs)
    st.number_input('Age:', min_value=1)
    st.text_input('Nom:')
    st.button('save')

st.subheader('List Sider:')

age  = st.slider('Votre âge', 0,100,25)
st.write(age)

st.subheader('Formulaire:')

with st.form(key='Mon formulaire'):
    texte = st.text_input(label='Votre texte')
    envoyer = st.form_submit_button(label='Envoyer')

if envoyer:
    st.write(texte)

st.subheader('File upload:')

photo = st.file_uploader('Choisir une image', ['.png','.jpg','.jpeg'])

if photo is not None:
    st.write('Name:', photo.name)
    st.image(photo.getvalue(), width=100)


st.subheader('Tabs:')

tab1,tab2,tab3 = st.tabs(['Chat','Chien','Lion'])

with tab1:
    st.header('Chat')
    st.image('data:image/jpeg;base64,')

with tab2:
    st.header('Chien')
    st.image('data:image/jpeg;base64,')

with tab3:
    st.header('Lion')
    st.image('data:image/jpeg;base64,')

st.subheader('Sidebar:')

st.sidebar.selectbox('Moyen de contact', ("Email", "Tél. mobile", "Tél. fixe"))

# sidebar avec le context manager

with st.sidebar:
    st.radio("Méthode d'envoi:", ("Standard (5-10 jours)", "Express (2-5 jours)"))

st.subheader("Session:")

# session est un dictionnaire utilisé par les applications web pour stocker des données.
# Tant que l'application est en cours d'exécution, le contenu de la session est maintenu en mémoire

if 'formation' not in st.session_state:
    st.session_state['formation'] = 'Python'
    st.write('Session créée')
else:
    contenu_session = st.session_state.get('formation')
    st.write(contenu_session)


st.toast('Fini', icon='💯')
st.snow()
st.balloons()